module RefModule(
  input clk,
  input reset,
  input serial_in,
  output serial_out,
  output reg [31:0] parallel_out
);reg [31:0] unused_shift_reg;

always @(posedge clk) begin
  if (reset) begin
    unused_shift_reg <= 0;
  end else begin
    unused_shift_reg <= {unused_shift_reg[30:0], serial_in};
  end
end

assign serial_out = unused_shift_reg[31];
assign parallel_out = unused_shift_reg;

endmodule
